from time import time

class RateLimiter:
    def __init__(self):
        self.last_request_time = 0
        self.limit_per_request = 10
        self.request_count = 0
        self.temporary_counter = 0

    def allow_request(self, timestamp: int) -> bool:
        request_time = time()

        # Check if the request count has exceeded the limit per request
        if self.request_count >= self.limit_per_request:
            return False

        if self.request_count == 60:
            # If it's a sliding window rate limiter, check for request within last 60 seconds
            if timestamp < self.last_request_time - (self.temporary_counter * 60):
                return True
            else: 
                return False

        self.request_count += 1

        # Check if the current request time has exceeded the limit
        if self.limit_per_request <= request_time:
            self.temporary_counter += 1

        self.last_request_time = timestamp

        return True

